// // This module compares two 32-bit inputs A and B and outputs three signals: A_greater, A_equal, and A_less, indicating whether A is less than, equal to, or greater than B, respectively.
module comparator_32bit (
    input [31:0] A,
    input [31:0] B,
    output reg A_greater,
    output reg A_equal,
    output reg A_less
);
    always @(*) begin
        if (A > B) begin
            A_greater = 1;
            A_equal = 0;
            A_less = 0;
        end else if (A == B) begin
            A_greater = 0;
            A_equal = 1;
            A_less = 0;
        end else begin
            A_greater = 0;
            A_equal = 0;
            A_less = 1;
        end
    end
endmodule
